"use client";
import { useHeaderStore } from "./headerStore";
import { PartyPopper,  } from "lucide-react";

export const Header = ({}) => {
    const headerState = useHeaderStore((state) => state.headerText);
    const setHeader = useHeaderStore((state) => state.setHeaderText);
    return (
        <div className="text-5xl">
            <PartyPopper className="w-[1em] h-[1em] text-green-700 fill-green-400 inline"/>
            <p className="inline" onClick={() => setHeader("lol")}>lalallala {headerState}</p>
        </div>
    );
};
